function normalizeApi5lXGrade(input) {
  const s = String(input || '').toUpperCase().replace(/\s+/g, ' ').trim();
  const match = s.match(/API\s*5L.*X\s*([0-9]{2})/);
  if (!match) return null;
  return `API_5L_X${match[1]}`;
}

function interpolate(x, x1, y1, x2, y2) {
  return y1 + ((x - x1) * (y2 - y1)) / (x2 - x1);
}

function getAllowableStressMPa(library, materialInput, designTempC) {
  const key = library.material_aliases[materialInput?.toUpperCase?.()] || normalizeApi5lXGrade(materialInput);
  if (!key) throw new Error('API 5L X grade not recognized.');
  const row = library.materials.find(m => m.key === key);
  if (!row) throw new Error(`No stress row found for ${key}.`);
  if (designTempC > row.max_use_temp_c) {
    throw new Error(`Design temperature ${designTempC} °C exceeds ASME row max use temperature ${row.max_use_temp_c} °C for ${row.display_name}.`);
  }
  const grid = library.temperature_grid_c.map(v => v === 'min_to_40' ? 40 : Number(v));
  if (designTempC <= 40) return { S_MPa: row.stress_mpa[0], material: row, warnings: ['Temperature is at or below 40 °C table column; check min_temp_code and impact test rules.'] };
  for (let i = 0; i < grid.length - 1; i++) {
    const x1 = grid[i], x2 = grid[i + 1];
    const y1 = row.stress_mpa[i], y2 = row.stress_mpa[i + 1];
    if (designTempC >= x1 && designTempC <= x2) {
      if (y1 == null || y2 == null) throw new Error('No ASME stress value available for interpolation in this temperature range.');
      return { S_MPa: interpolate(designTempC, x1, y1, x2, y2), material: row, warnings: [] };
    }
  }
  if (designTempC > 200 && designTempC <= row.max_use_temp_c) {
    return { S_MPa: row.stress_mpa[4], material: row, warnings: ['Design temperature is above 200 °C but not above 204 °C max use temperature; verify use of 200 °C table value with engineer.'] };
  }
  throw new Error('Temperature outside available stress grid.');
}
